Bisa banget! JWT auth itu standard buat modern web apps. Gue jelasin step by step ya:

**1. Install dependencies:**
```bash
npm install jsonwebtoken bcrypt
```

**2. Setup login endpoint:**
```javascript
const jwt = require('jsonwebtoken');
const bcrypt = require('bcrypt');

app.post('/login', async (req, res) => {
  const { email, password } = req.body;

  // Cari user di database
  const user = await User.findOne({ email });
  if (!user) return res.status(401).json({ error: 'User not found' });

  // Verify password
  const validPassword = await bcrypt.compare(password, user.password);
  if (!validPassword) return res.status(401).json({ error: 'Wrong password' });

  // Generate token
  const token = jwt.sign(
    { userId: user._id, email: user.email },
    process.env.JWT_SECRET,
    { expiresIn: '7d' }
  );

  res.json({ token });
});
```

**3. Middleware untuk protect routes:**
```javascript
function authMiddleware(req, res, next) {
  const token = req.header('Authorization')?.replace('Bearer ', '');

  if (!token) return res.status(401).json({ error: 'Access denied' });

  try {
    const verified = jwt.verify(token, process.env.JWT_SECRET);
    req.user = verified;
    next();
  } catch (err) {
    res.status(401).json({ error: 'Invalid token' });
  }
}
```

Nah itu basic flow-nya. Jangan lupa:
- Set JWT_SECRET di .env (pakai string random yang panjang)
- Hash password pakai bcrypt sebelum save ke DB
- Di production, pakai HTTPS buat kirim token

